1	import 'react-native-url-polyfill/auto';
2	import { createClient } from '@supabase/supabase-js';
3	import Constants from 'expo-constants';
4	import type { Database } from '@/types/supabase';
5	import { getCachedToken } from './storage';
6	
7	type Extra = {
8	  SUPABASE_URL?: string;
9	  SUPABASE_ANON_KEY?: string;
10	};
11	
12	const extra = (Constants.expoConfig?.extra ?? {}) as Extra;
13	
14	if (!extra.SUPABASE_URL || !extra.SUPABASE_ANON_KEY) {
15	  throw new Error(
16	    'Missing SUPABASE_URL or SUPABASE_ANON_KEY. Populate .env and rebuild the Expo config.',
17	  );
18	}
19	
20	// Inject our custom-issued Marketify JWT on every request. We read from the
21	// in-memory cache in `storage.ts` (AuthProvider keeps it in lock-step with
22	// SecureStore) so this stays synchronous. signIn / signOut mutate the cache
23	// and the next request picks it up — no client recreation needed.
24	const marketifyFetch: typeof fetch = (input, init) => {
25	  const token = getCachedToken();
26	  if (!token) {
27	    return fetch(input, init);
28	  }
29	  const headers = new Headers(init?.headers);
30	  headers.set('Authorization', `Bearer ${token}`);
31	  return fetch(input, { ...init, headers });
32	};
33	
34	export const supabase = createClient<Database>(extra.SUPABASE_URL, extra.SUPABASE_ANON_KEY, {
35	  auth: {
36	    // We issue our own JWT via edge functions — disable Supabase Auth's
37	    // session handling so it doesn't fight the Authorization header above.
38	    persistSession: false,
39	    autoRefreshToken: false,
40	    detectSessionInUrl: false,
41	  },
42	  global: {
43	    fetch: marketifyFetch,
44	  },
45	});
46

1	import {
2	  createContext,
3	  useCallback,
4	  useContext,
5	  useEffect,
6	  useMemo,
7	  useState,
8	  type ReactNode,
9	} from 'react';
10	import type { Database } from '@/types/supabase';
11	import {
12	  clearPersistedAuth,
13	  hydrateTokenFromStorage,
14	  persistToken,
15	  persistUserRaw,
16	  readPersistedUserRaw,
17	} from './storage';
18	
19	export type AuthUser = Database['public']['Tables']['users']['Row'];
20	export type AuthRole = Database['public']['Enums']['user_role'];
21	
22	type AuthContextValue = {
23	  user: AuthUser | null;
24	  role: AuthRole | null;
25	  signIn: (token: string, user: AuthUser) => void;
26	  signOut: () => void;
27	};
28	
29	const AuthContext = createContext<AuthContextValue | null>(null);
30	
31	function isAuthUserShape(value: unknown): value is AuthUser {
32	  if (!value || typeof value !== 'object') return false;
33	  const v = value as Record<string, unknown>;
34	  return (
35	    typeof v.id === 'string' &&
36	    typeof v.username === 'string' &&
37	    (v.role === 'creator' || v.role === 'lister')
38	  );
39	}
40	
41	export function AuthProvider({ children }: { children: ReactNode }) {
42	  const [user, setUser] = useState<AuthUser | null>(null);
43	  const [hydrated, setHydrated] = useState(false);
44	
45	  useEffect(() => {
46	    let active = true;
47	    (async () => {
48	      try {
49	        await hydrateTokenFromStorage();
50	        const raw = await readPersistedUserRaw();
51	        if (!active) return;
52	        if (!raw) {
53	          setHydrated(true);
54	          return;
55	        }
56	        try {
57	          const parsed: unknown = JSON.parse(raw);
58	          if (isAuthUserShape(parsed)) {
59	            setUser(parsed);
60	          } else {
61	            await clearPersistedAuth();
62	          }
63	        } catch {
64	          await clearPersistedAuth();
65	        }
66	      } finally {
67	        if (active) setHydrated(true);
68	      }
69	    })();
70	    return () => {
71	      active = false;
72	    };
73	  }, []);
74	
75	  const signIn = useCallback((token: string, nextUser: AuthUser) => {
76	    // Optimistic UI: state flips immediately; persistence is best-effort.
77	    // The token cache in `storage.ts` is updated synchronously inside
78	    // `persistToken` so the next Supabase request sees the new JWT even
79	    // before the SecureStore write settles.
80	    setUser(nextUser);
81	    void persistToken(token);
82	    void persistUserRaw(JSON.stringify(nextUser));
83	  }, []);
84	
85	  const signOut = useCallback(() => {
86	    setUser(null);
87	    void clearPersistedAuth();
88	  }, []);
89	
90	  const value = useMemo<AuthContextValue>(
91	    () => ({
92	      user,
93	      role: user?.role ?? null,
94	      signIn,
95	      signOut,
96	    }),
97	    [user, signIn, signOut],
98	  );
99	
100	  if (!hydrated) {
101	    return null;
102	  }
103	
104	  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
105	}
106	
107	export function useAuth(): AuthContextValue {
108	  const ctx = useContext(AuthContext);
109	  if (!ctx) {
110	    throw new Error('useAuth must be used inside an AuthProvider.');
111	  }
112	  return ctx;
113	}
